from elasticsearch import Elasticsearch
import logging
import json
from datetime import datetime
from typing import Dict, List, Any

class CentralizedLogger:
    def __init__(self, es_host: str = "localhost:9200"):
        self.es = Elasticsearch([es_host])
        self.index_name = "logs"
        self._create_index()
        self._setup_logging()
    
    def _create_index(self):
        mapping = {
            "mappings": {
                "properties": {
                    "timestamp": {"type": "date"},
                    "level": {"type": "keyword"},
                    "message": {"type": "text"},
                    "service": {"type": "keyword"},
                    "host": {"type": "keyword"},
                    "tags": {"type": "keyword"}
                }
            }
        }
        if not self.es.indices.exists(index=self.index_name):
            self.es.indices.create(index=self.index_name, body=mapping)
    
    def _setup_logging(self):
        self.logger = logging.getLogger('centralized_logger')
        self.logger.setLevel(logging.DEBUG)
        
        handler = logging.StreamHandler()
        formatter = logging.Formatter(
            '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
        )
        handler.setFormatter(formatter)
        self.logger.addHandler(handler)
    
    def log_message(self, level: str, message: str, service: str = "unknown", 
                   host: str = "localhost", tags: List[str] = None):
        log_entry = {
            "timestamp": datetime.now().isoformat(),
            "level": level,
            "message": message,
            "service": service,
            "host": host,
            "tags": tags or []
        }
        
        try:
            self.es.index(
                index=self.index_name,
                body=log_entry
            )
            self.logger.info(f"Logged message: {message}")
        except Exception as e:
            self.logger.error(f"Failed to log message: {e}")
    
    def search_logs(self, query: str, size: int = 100, 
                   level: str = None, service: str = None) -> List[Dict]:
        search_body = {
            "query": {
                "bool": {
                    "must": [
                        {
                            "multi_match": {
                                "query": query,
                                "type": "best_fields",
                                "fields": ["message", "service", "host"]
                            }
                        }
                    ]
                }
            },
            "size": size,
            "sort": [{"timestamp": {"order": "desc"}}]
        }
        
        if level:
            search_body["query"]["bool"]["filter"] = [{"term": {"level": level}}]
        
        if service:
            if "bool" not in search_body["query"]:
                search_body["query"]["bool"] = {"must": [], "filter": []}
            search_body["query"]["bool"]["filter"].append({"term": {"service": service}})
        
        try:
            response = self.es.search(
                index=self.index_name,
                body=search_body
            )
            return [hit["_source"] for hit in response["hits"]["hits"]]
        except Exception as e:
            self.logger.error(f"Search failed: {e}")
            return []

class SearchPlatform:
    def __init__(self, es_host: str = "localhost:9200"):
        self.es = Elasticsearch([es_host])
        self.search_index = "search_docs"
        self._create_search_index()
    
    def _create_search_index(self):
        mapping = {
            "mappings": {
                "properties": {
                    "title": {"type": "text"},
                    "content": {"type": "text"},
                    "category": {"type": "keyword"},
                    "tags": {"type": "keyword"},
                    "created_at": {"type": "date"}
                }
            }
        }
        if not self.es.indices.exists(index=self.search_index):
            self.es.indices.create(index=self.search_index, body=mapping)
    
    def index_document(self, title: str, content: str, category: str = "general", 
                      tags: List[str] = None):
        doc = {
            "title": title,
            "content": content,
            "category": category,
            "tags": tags or [],
            "created_at": datetime.now().isoformat()
        }
        
        try:
            self.es.index(
                index=self.search_index,
                body=doc
            )
            logging.info(f"Indexed document: {title}")
        except Exception as e:
            logging.error(f"Failed to index document: {e}")
    
    def search_documents(self, query: str, size: int = 50, 
                        category: str = None) -> List[Dict]:
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "type": "best_fields",
                    "fields": ["title", "content", "tags"]
                }
            },
            "size": size,
            "sort": [{"created_at": {"order": "desc"}}]
        }
        
        if category:
            search_body["query"]["bool"] = {
                "must": [search_body["query"]["multi_match"]],
                "filter": [{"term": {"category": category}}]
            }
            del search_body["query"]["multi_match"]
        
        try:
            response = self.es.search(
                index=self.search_index,
                body=search_body
            )
            return [hit["_source"] for hit in response["hits"]["hits"]]
        except Exception as e:
            logging.error(f"Search failed: {e}")
            return []

